from typing import List
from collections import deque

def solve(grid: List[List[int]]) -> int:
    m, n = len(grid), len(grid[0])
    xor = [[0] * n for _ in range(m)]

    # Calculate XOR from (0, 0) to each cell
    xor[0][0] = grid[0][0]
    for i in range(m):
        for j in range(n):
            if i == 0 and j == 0:
                continue
            if i == 0:
                xor[i][j] = xor[i][j-1] ^ grid[i][j]
            elif j == 0:
                xor[i][j] = xor[i-1][j] ^ grid[i][j]
            else:
                xor[i][j] = min(xor[i-1][j], xor[i][j-1]) ^ grid[i][j]

    # Use BFS to find the minimum XOR value
    queue = deque()
    queue.append((0, 0))
    visited = [[False] * n for _ in range(m)]
    visited[0][0] = True
    min_xor = xor[0][0]

    while queue:
        i, j = queue.popleft()
        if i == m - 1 and j == n - 1:
            return min_xor
        for ni, nj in [(i+1, j), (i, j+1)]:
            if 0 <= ni < m and 0 <= nj < n and not visited[ni][nj]:
                visited[ni][nj] = True
                queue.append((ni, nj))
                current_xor = xor[ni][nj]
                if current_xor < min_xor:
                    min_xor = current_xor

    return min_xor
